from user_service import create_user, deactivate_user, get_user_domain
from newsletter import subscribe, unsubscribe, SUBSCRIBERS
from contact_form import submit_contact, get_pending_contacts

def run_tests():
    errors = []

    # Test 1: valid user creation
    try:
        u = create_user("Alice", "  Alice@Example.COM  ")
        assert u["email"] == "alice@example.com", f"Expected normalized email, got {u['email']}"
        assert u["active"] == True
    except Exception as e:
        errors.append(f"Test 1 failed: {e}")

    # Test 2: invalid email raises
    try:
        create_user("Bob", "not-an-email")
        errors.append("Test 2 failed: should have raised ValueError")
    except ValueError:
        pass
    except Exception as e:
        errors.append(f"Test 2 failed: unexpected error {e}")

    # Test 3: empty email raises
    try:
        create_user("Carol", "")
        errors.append("Test 3 failed: should have raised ValueError")
    except ValueError:
        pass

    # Test 4: None email raises
    try:
        create_user("Dave", None)
        errors.append("Test 4 failed: should have raised ValueError")
    except ValueError:
        pass

    # Test 5: newsletter subscribe
    try:
        entry = subscribe("  Test@News.COM  ")
        assert entry["email"] == "test@news.com"
        assert entry["preferences"] == ["general"]
    except Exception as e:
        errors.append(f"Test 5 failed: {e}")

    # Test 6: newsletter with preferences
    try:
        entry = subscribe("pref@test.com", ["tech", "science"])
        assert entry["preferences"] == ["tech", "science"]
    except Exception as e:
        errors.append(f"Test 6 failed: {e}")

    # Test 7: contact form
    try:
        c = submit_contact("  Eve  ", "eve@test.com", "  Hello!  ")
        assert c["name"] == "Eve"
        assert c["email"] == "eve@test.com"
        assert c["message"] == "Hello!"
        assert c["status"] == "pending"
    except Exception as e:
        errors.append(f"Test 7 failed: {e}")

    # Test 8: contact form missing name
    try:
        submit_contact("", "e@t.com", "msg")
        errors.append("Test 8 failed: should have raised ValueError")
    except ValueError:
        pass

    # Test 9: deactivate user
    try:
        u = create_user("Frank", "frank@test.com")
        u = deactivate_user(u)
        assert u["active"] == False
    except Exception as e:
        errors.append(f"Test 9 failed: {e}")

    # Test 10: get_user_domain
    try:
        u = create_user("Grace", "grace@example.org")
        assert get_user_domain(u) == "example.org"
    except Exception as e:
        errors.append(f"Test 10 failed: {e}")

    if errors:
        for e in errors:
            print(f"FAIL: {e}")
        raise AssertionError(f"{len(errors)} test(s) failed")

    print(f"All 10 tests passed")
    return True

if __name__ == "__main__":
    run_tests()

